async function getFailedJobs(octokit, owner, repo, runId) {
  const {
    data: { jobs }
  } = await octokit.rest.actions.listJobsForWorkflowRun({
    owner,
    repo,
    run_id: runId,
    filter: "latest"
  });
  const failedJobs = [];
  for (const job of jobs) {
    if (job.conclusion !== "failure") continue;
    const failedStep = job.steps?.find((s) => s.conclusion === "failure");
    const annotations = await getJobAnnotations(octokit, owner, repo, job.id);
    failedJobs.push({
      id: job.id,
      name: job.name,
      conclusion: job.conclusion,
      failed_step: failedStep?.name,
      annotations
    });
  }
  return failedJobs;
}
async function getJobAnnotations(octokit, owner, repo, jobId) {
  try {
    const { data } = await octokit.rest.checks.listAnnotations({
      owner,
      repo,
      check_run_id: jobId,
      per_page: 50
    });
    return data.map(
      (a) => ({
        level: a.annotation_level === "failure" ? "failure" : "warning",
        path: a.path ?? "",
        line: a.start_line ?? 0,
        message: a.message ?? ""
      })
    );
  } catch (error) {
    core4.warning(`Failed to fetch annotations for job ${jobId}: ${error instanceof Error ? error.message : String(error)}`);
    return [];
  }
}
async function getWorkflowSummary(octokit, owner, repo, runId) {
  const { data: run2 } = await octokit.rest.actions.getWorkflowRun({
    owner,
    repo,
    run_id: runId
  });
  const failedJobs = await getFailedJobs(octokit, owner, repo, runId);
  return {
    workflow: run2.name ?? "unknown",
    run_id: runId,
    run_attempt: run2.run_attempt ?? 1,
    failed_jobs: failedJobs
  };
}

